 // TABS
 function goTab(n){
   if(n<0||n>=TABS)return;
   curTab=n;
   qa('.tab').forEach(function(t){t.classList.toggle('on',parseInt(t.getAttribute('data-t'))===n);});
   qa('.tpane').forEach(function(p){p.classList.toggle('on',parseInt(p.getAttribute('data-p'))===n);});
   el('nav_prev').disabled=(n===0);
   el('nav_next').disabled=(n===TABS-1);
   var tb=qa('.tab')[n];if(tb)tb.scrollIntoView({behavior:'smooth',block:'nearest',inline:'center'});
   document.querySelector('.paper').scrollIntoView({behavior:'smooth',block:'start'});
 }
 qa('.tab').forEach(function(t){t.addEventListener('click',function(){goTab(parseInt(t.getAttribute('data-t')));});});
