   el('jutsu_list').appendChild(it);
   it.querySelector('.rm').addEventListener('click',function(){rm(this);});
   it.querySelector('.confbtn').addEventListener('click',function(){
     var card=this.closest('.item');
     if(card.classList.contains('confirmed')){return;}
     card.classList.add('confirmed');
     qa('input,select,textarea',card).forEach(function(inp){inp.disabled=true;});
     this.textContent=L==='th'?'แก้ไข':'EDIT';
     this.className='editbtn';
     this.addEventListener('click',function editHandler(){
       card.classList.remove('confirmed');
       qa('input,select,textarea',card).forEach(function(inp){inp.disabled=false;});
       var btn=document.createElement('button');btn.className='confbtn';btn.setAttribute('data-en','✓ CONFIRM THIS JUTSU');btn.setAttribute('data-th','✓ ยืนยันจุตสึนี้');btn.textContent=L==='th'?'✓ ยืนยันจุตสึนี้':'✓ CONFIRM THIS JUTSU';
       card.replaceChild(btn,card.querySelector('.editbtn'));
       btn.addEventListener('click',function(){
         card.classList.add('confirmed');
         qa('input,select,textarea',card).forEach(function(inp){inp.disabled=true;});
         btn.textContent=L==='th'?'แก้ไข':'EDIT';btn.className='editbtn';
         btn.addEventListener('click',editHandler);
       });
     });
   });
   applyText();applyPlace();
 }

